import RestoData from '../../data/resto-data';
import CONFIG from '../../globals/config';
import UrlParser from '../../routes/url-parser';
import LikeButtonInitiator from '../../utils/like-btn-initiator';
import { createRestoDetailPage, heroImage } from '../templates/templates';

const RestoDetails = {
  async renderPage() {
    return `
    <div class="resto-details" id="restoDetails"></div>
    <div class="like-btn-container" id="likeBtnContainer"></div>`;
  },
  async afterRenderPage() {
    const restoDetails = document.querySelector('#restoDetails');
    const heroDiv = document.querySelector('#heroDiv');
    const url = UrlParser.parseActiveUrlWithoutCombiner();
    const restoDetailsData = await RestoData.details(url.id);
    const reviewArray = await restoDetailsData.customerReviews;
    heroDiv.innerHTML = heroImage(
      `${CONFIG.IMG_URL}small/${restoDetailsData.pictureId}`,
      `${CONFIG.IMG_URL}large/${restoDetailsData.pictureId}`,
      restoDetailsData.name
    );
    restoDetails.innerHTML = createRestoDetailPage(
      restoDetailsData,
      reviewArray
    );

    LikeButtonInitiator.init({
      likeButtonContainer: document.querySelector('#likeBtnContainer'),
      resto: restoDetailsData,
    });

    const reviewForm = document.querySelector('#reviewForm');
    reviewForm.addEventListener('submit', async (event) => {
      event.preventDefault();
      await RestoData.postReview({
        id: restoDetailsData.id,
        name: document.querySelector('#reviewName').value,
        review: document.querySelector('#reviewContent').value,
      });
      this.afterRenderPage();
    });
  },
};

export default RestoDetails;
