import CONFIG from '../../globals/config';

class RestoCard extends HTMLElement {
  #shadowRoot = null;
  #style = null;
  #lazyLoad = null;
  #restoData = {
    id: null,
    name: null,
    description: null,
    pictureId: null,
    city: null,
    rating: null,
  };

  constructor() {
    super();
    this.#shadowRoot = this.attachShadow({ mode: 'open' });
    this.#style = document.createElement('style');
  }

  /**
   * @param {boolean} value
   */
  set lazyLoad(value){
    this.#lazyLoad = value;
  }
  /**
   * @param {{ id: any; name?: null; description?: null; pictureId?: null; city?: null; rating?: null; }} value
   */

  set restoData(value) {
    this.#restoData = value;
    this.id = value.id;
    this.render();
  }

  #emptyContent() {
    this.#shadowRoot.innerHTML = `
      <article tabindex="0">
        <div class="img-container">
          <img
              loading=${this.#lazyLoad === true? 'lazy': 'eager'}
              src="${CONFIG.IMG_URL}medium/${this.#restoData.pictureId}"
              alt="${this.#restoData.name}"
          />
        </div>

            <div class="text-container">
              <h3>${this.#restoData.name}</h3>
              <h4>Kota: ${this.#restoData.city}</h4>
              <p>Rating: ${this.#restoData.rating}</p>
              <p class="resto-desc">${this.#restoData.description}</p>
              <a href="#/details/${this.#restoData.id}">See more details...</a>
            </div>
      </article>`;
  }

  #updateStyle() {
    this.#style.innerHTML = `
    :host{
      border-radius: 5px;
      border: none;
      font-family: Poppins;
    }
    .img-container{
      width:auto;
      max-height:200px;
    }
    img{
      width: 100%;
      max-height: 200px;
      object-fit: cover;
    }
    .text-container{
      padding: 10px;
    } 
    .resto-desc{
      max-height: 7em;
      overflow:hidden;
    }
    a{
      display:block;
      height:44px;
      min-width:44px;
    }
    `;
  }

  render() {
    this.#emptyContent();
    this.#updateStyle();
    this.#shadowRoot.appendChild(this.#style);
    this.#shadowRoot.innerHTML += '';
  }
}

customElements.define('resto-card', RestoCard);
