const heroImage = (
  smallSrc = './images/heros/hero-image_3-small.jpg',
  largeSrc = './images/heros/hero-image_3-large.jpg',
  alt = 'Dark background, with a few dim lights in the distance.'
) => `
  <picture>
    <source media="(max-width: 600px)" srcset=${smallSrc}>
    <img
    src="${largeSrc}"
    alt="${alt}"
    />
  </picture>`;

const createRestoDetailPage = (detail, reviewArray) => `
    <h3>${detail.name}</h3>
    <h4>Rating: ${detail.rating}</h4>
    <h4>Kota: ${detail.city}</h4>
    <h5>Alamat: ${detail.address}</h5>
    <p>${detail.description}</p>
    <div id="menu" class="menu">
        <div id="drinkMenu" class="drink-menu"><h5>Minuman</h5>${itemArrayHelper(
    detail.menus.drinks
  )}</div>
        <div id="foodMenu" class="food-menu"><h5>Makanan</h5>${itemArrayHelper(
    detail.menus.foods
  )}</div>
    </div>
    <div id="reviews" class="reviews">
      ${reviewForm}
      ${iterateReviews(reviewArray)}
    </div>`;

const itemArrayHelper = (itemArray) => {
  let html = '';
  for (const item of itemArray) {
    html += `<p >${item.name}</p>`;
  }
  return html;
};

const reviewForm = `
  <form id="reviewForm" class="review-form">
    <h5>Leave a review</h5>
    <label for="reviewName">Name</label>
    <input type="text"id="reviewName">
    <label for="reviewContent">Review</label>
    <textarea name="" id="reviewContent"></textarea>
    <button id="submitButton">Submit</button>
  </form>`;

const iterateReviews = (reviewArray) => {
  let reviewsHtml = '';
  reviewArray.forEach((review) => {
    reviewsHtml += createReviewDisplay(review);
  });
  return reviewsHtml;
};

const createReviewDisplay = (review) => `
    <div id="userReview">
      <h5>${review.name}</h5>
      <p>${review.review}</p>
    </div>`;

const createLikeButtonTemplate = () => `
  <button aria-label="like this restaurant" id="likeButton" class="like">
  </button>
`;

const createRemoveLikeButtonTemplate = () => `
  <button aria-label="remove like from this restaurant" id="likeButton" class="unlike">
  </button>
`;
export { heroImage, createRestoDetailPage, createLikeButtonTemplate, createRemoveLikeButtonTemplate };
